mapper.select:
/*AcenCnsltCanMapper.getAcenCnsltTransferDate*/
SELECT ETC1
FROM CMN_GRP_CD_MST
WHERE GRP_ID = 'DEV0003'
  AND USG_YN = 'Y'
  AND CD_VAL = #{cdVal}

mapper.update:
		/*AcenCnsltCanMapper.updateAcenCnsltMst*/
		UPDATE NMCP_ACEN_CNSLT_MST@DL_MCP
		SET TALK_TEL_NO = NVL2(TALK_TEL_NO, '00000000000', NULL)
           ,TALK_NM = NVL2(TALK_NM, '이관고객', NULL)
		WHERE CNSLT_SEQ = #{cnsltSeq}

		/*AcenCnsltCanMapper.updateAcenCnsltDtl*/
		UPDATE  NMCP_ACEN_CNSLT_DTL@DL_MCP
		SET AGE = ''
		  ,BIRTH_DT = ''
          ,GENDER = ''
		WHERE CNSLT_SEQ = #{cnsltSeq}

mapper.select:
/*AcenCnsltCanMapper.getAcenCnsltMstCanList*/
SELECT CNSLT_SEQ
FROM NMCP_ACEN_CNSLT_MST@DL_CAN
WHERE RVISN_DTTM < TRUNC(SYSDATE) - #{stdrDay}
